return [{ json: {
  team: [
    { name: 'Alex Chen', role: 'Senior FE', skills: ['React', 'TypeScript', 'CSS', 'Performance optimisation', 'Code review'] },
    { name: 'Maria Santos', role: 'Backend Engineer', skills: ['Node.js', 'PostgreSQL', 'REST API design', 'Auth', 'Redis'] },
    { name: 'James Kim', role: 'Product Designer', skills: ['Figma', 'User research', 'Prototyping', 'Design systems', 'Accessibility'] },
    { name: 'Sofia Park', role: 'Junior FE', skills: ['React basics', 'HTML/CSS', 'Git'] },
    { name: 'David Osei', role: 'Backend Engineer', skills: ['Node.js', 'GraphQL', 'PostgreSQL', 'API design'] }
  ],
  upcoming_work: [
    { title: 'Mobile app (React Native) — Q3 launch', priority: 'high', required_skills: ['React Native', 'Mobile UX patterns', 'App Store deployment'] },
    { title: 'AI-powered task suggestions (OpenAI integration)', priority: 'high', required_skills: ['LLM API integration', 'Prompt engineering', 'Cost monitoring'] },
    { title: 'Enterprise SSO (SAML/OIDC)', priority: 'medium', required_skills: ['SAML', 'OIDC', 'Security best practices'] },
    { title: 'Real-time collaboration (WebSockets)', priority: 'medium', required_skills: ['WebSockets', 'Conflict resolution', 'State synchronisation'] }
  ],
  quarter: 'Q3 2026'
} }];

const ctx = $input.first().json;
const teamText = ctx.team.map(m => `  ${m.name} (${m.role}): ${m.skills.join(', ')}`).join('
');
const workText = ctx.upcoming_work.map(w => `  [${w.priority.toUpperCase()}] ${w.title}: needs ${w.required_skills.join(', ')}`).join('
');
const system = `You are a technical talent development advisor. You analyse a team's current skills against upcoming work to identify the most impactful knowledge gaps. You prioritise by business impact, and you give specific, actionable learning path recommendations — not generic advice. Return ONLY valid JSON.`;
const user = `Identify knowledge gaps for the team going into ${ctx.quarter}.

Team skills inventory:
${teamText}

Upcoming high-priority work:
${workText}

Return JSON:
{
  "gaps": [
    {
      "skill": "string",
      "missing_from": ["team member names"],
      "required_for": ["project title"],
      "priority": "critical|high|medium",
      "impact_if_unaddressed": "string",
      "learning_path": {
        "recommended_resource": "string",
        "estimated_days": 5,
        "who_should_lead": "string"
      }
    }
  ],
  "strengths_to_leverage": ["string — where the team is strong and should lead this work"],
  "hiring_recommendation": "string|null — only if there is a gap no internal learning can bridge in time",
  "quarter_readiness_assessment": "string — overall team readiness for Q3 work"
}`;
return [{ json: { ctx, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Gap Analysis Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.gaps || !Array.isArray(parsed.gaps)) return [{ json: { _error: true, reason: 'Missing gaps array' } }];
const critical = parsed.gaps.filter(g => g.priority === 'critical').length;
return [{ json: { _error: false, analysis: parsed, ctx: upstream.ctx, meta: { quarter: upstream.ctx.quarter, gap_count: parsed.gaps.length, critical_count: critical, generated_at: new Date().toISOString() } } }];
